mapper.select:
/* SQL ID : OrgAbsentRatioDAO.list 설 명 : 결시원 성적비율 리스트 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY ABSNCE_GBNCD, EXAM_GBNCD) AS lineNo , ORG_ID AS orgId , ABSNCE_GBNCD AS absentGbn , (SELECT CDNM FROM TB_SYS_CODE WHERE CTGRCD = 'ABSENT_SCORE_GBN_CD' AND CD = ABSNCE_GBNCD) AS absentGbnNm , EXAM_GBNCD AS examGbn , (SELECT CDNM FROM TB_SYS_CODE WHERE CTGRCD = 'ABSENT_SCORE_EXAM_CD' AND CD = EXAM_GBNCD) AS examGbnNm , ABSNCE_RFLTRT AS scorRatio , ABSNCE_EXPLN AS absentDesc , RGTR_ID AS rgtrId , FRST_INQ_DTTM AS regDttm , MDFR_ID AS mdfrId , MOD_DTTM AS modDttm FROM TB_LMS_MRK_ABSNCE_RFLTRT WHERE 1 = 1
AND ABSNCE_GBNCD = #{absentGbn}
AND EXAM_GBNCD = #{examGbn}
AND ORG_ID = #{orgId}
ORDER BY ABSNCE_GBNCD, EXAM_GBNCD

mapper.insert:
		/*
             SQL ID : OrgAbsentRatioDAO.insert
            	 설  명 : 결시원 성적비율 등록
         */
         INSERT INTO TB_LMS_MRK_ABSNCE_RFLTRT (
         	  ORG_ID
			, ABSNCE_GBNCD
			, EXAM_GBNCD
			, ABSNCE_RFLTRT
			, ABSNCE_EXPLN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
         ) VALUES (
         	  #{orgId}
         	, #{absentGbn}
         	, #{examGbn}
         	, #{scorRatio}
         	, #{absentDesc}
         	, #{rgtrId}
         	, FN_DTTM()
         	, #{mdfrId}
         	, FN_DTTM()
         )
         ON DUPLICATE KEY UPDATE
        	   ABSNCE_RFLTRT = #{scorRatio}
	 	   	 , ABSNCE_EXPLN = #{absentDesc}
		     , MDFR_ID = #{mdfrId}
		     , MOD_DTTM = FN_DTTM()

mapper.delete:
		/*
             SQL ID : OrgAbsentRatioDAO.delete
            	 설  명 : 결시원 성적비율 삭제
         */
         DELETE FROM TB_LMS_MRK_ABSNCE_RFLTRT
          WHERE ORG_ID = #{orgId}
            AND ABSNCE_GBNCD = #{absentGbn}
            AND EXAM_GBNCD = #{examGbn}
